//! Instance methods of the rune standard library (rune 0.14.2), grouped by
//! the module that registers them — mirror of `rune::modules::*`, so a host
//! that installs only some modules can assemble the matching subset.
//!
//! GENERATED from the installed `Context::with_default_modules()` via the
//! `rune doc` CLI — do not edit by hand; regenerate after a rune upgrade
//! (see the ytaq project notes for the dump tooling).
//!
//! [`iter()`] carries the `Iterator`/`DoubleEndedIterator`/
//! `ExactSizeIterator` trait methods for all iterator-like types (whichever
//! module defines them) — without `std::iter` installed they do not exist
//! at runtime either.

use crate::types::{EnumVariant, MethodSignature, PrimitiveType, TypeDef};

fn ret(name: &str) -> Option<TypeDef> {
	match name {
		"" | "any" => None,
		"String" => Some(TypeDef::Primitive(PrimitiveType::String)),
		"bool" => Some(TypeDef::Primitive(PrimitiveType::Bool)),
		"i64" | "u64" => Some(TypeDef::Primitive(PrimitiveType::Int)),
		"f64" => Some(TypeDef::Primitive(PrimitiveType::Float)),
		"Bytes" => Some(TypeDef::Primitive(PrimitiveType::Bytes)),
		"Vec" => Some(TypeDef::List(Box::new(TypeDef::Unit))),
		"Object" => Some(TypeDef::Object(Vec::new())),
		other => Some(TypeDef::Enum(vec![EnumVariant {
			path: vec![other.to_string()],
			inner: None,
		}])),
	}
}

fn table(rows: &[(&str, &str, &str)]) -> Vec<MethodSignature> {
	rows.iter()
		.map(|(receiver, name, return_name)| MethodSignature::new(receiver, name, ret(return_name)))
		.collect()
}

