/// The whole standard library — for hosts using
/// `Context::with_default_modules()`.
pub fn rune_std_methods() -> Vec<MethodSignature> {
	let mut out = Vec::new();
	out.extend(string());
	out.extend(bytes());
	out.extend(vec());
	out.extend(object());
	out.extend(tuple());
	out.extend(hash_map());
	out.extend(hash_set());
	out.extend(vec_deque());
	out.extend(char());
	out.extend(i64());
	out.extend(u64());
	out.extend(f64());
	out.extend(option());
	out.extend(result());
	out.extend(iter());
	out.extend(ops());
	out.extend(generator());
	out.extend(mem());
	out.extend(test());
	out.extend(stream());
	out
}
